// ============================================
// BUILD GEMINI PROMPT from user input
// ============================================

const input = $input.first().json.body;

// Format projects
const projectsText = (input.projects || []).map((p, i) => {
  let line = `  ${i + 1}. ${p.name}: ${p.description}`;
  if (p.repoLink) line += ` | Repo: ${p.repoLink}`;
  return line;
}).join('\n');

// Format experience
const experienceText = (input.experience || []).length > 0
  ? (input.experience || []).map((e, i) => {
      let line = `  ${i + 1}. ${e.title} at ${e.company}`;
      if (e.duration) line += ` (${e.duration})`;
      if (e.location) line += ` — ${e.location}`;
      if (e.description) line += `\n     ${e.description}`;
      return line;
    }).join('\n')
  : '  No formal work experience yet (fresh graduate / student)';

// Format skills
const skillsText = Array.isArray(input.skills) ? input.skills.join(', ') : input.skills;

// Build the prompt
const prompt = `You are an expert ATS-optimized resume writer with 15 years of experience in HR and recruiting.

CANDIDATE PROFILE:
- Full Name: ${input.name}
- Email: ${input.email} | Phone: ${input.phone}
- GitHub: ${input.github || 'N/A'} | LinkedIn: ${input.linkedin || 'N/A'}
- City: ${input.city}
- Education:
  - School: ${input.school}
  - College: ${input.college} (Year: ${input.collegeYear})
  - 12th Standard Percentage: ${input.twelfthPercentage}%
  - CGPA: ${input.cgpa}
- Languages Known: ${input.languages}
- Technical Skills: ${skillsText}
- Projects:
${projectsText}
- Work Experience:
${experienceText}

TARGET JOB DESCRIPTION:
${input.jobDescription}

INSTRUCTIONS:
1. Carefully analyze the job description above and extract all key skills, tools, technologies, frameworks, and keywords.
2. Match them against the candidate's profile — prioritize relevant skills and projects.
3. Generate a tailored, ATS-friendly, professional resume.
4. Resume sections (in order): Contact Header → Professional Summary (3-4 lines) → Technical Skills → Projects → Work Experience (if any) → Education → Languages
5. In the Professional Summary, weave in keywords from the job description naturally.
6. For Projects, emphasize technologies and outcomes that match the job requirements.
7. Use strong action verbs (Developed, Implemented, Designed, Optimized, Deployed, etc.).
8. Add quantifiable results where reasonable (e.g., "reduced load time by 40%").

FORMATTING & OUTPUT RULES:
- Return ONLY clean, valid HTML — nothing else.
- Use inline CSS styles on every element (the HTML will be converted to DOCX, so no external CSS).
- Use a single-column layout for maximum ATS compatibility.
- Font: Calibri or Arial, size 11pt for body, 14pt for name, 12pt for section headings.
- Use a clean, modern, professional design with adequate spacing.
- Section headings should have a bottom border (border-bottom: 2px solid #2c3e50).
- Use bullet points (ul/li) for skills, project details, and experience points.
- Do NOT use tables for layout.
- Do NOT include images, icons, or special characters.
- Do NOT wrap output in markdown code fences.
- Start with <!DOCTYPE html> and end with </html>.`;

// Store both the prompt and the original input (for filename later)
return [{
  json: {
    prompt: prompt,
    candidateName: input.name
  }
}];

// ============================================
// EXTRACT clean HTML from Gemini response
// ============================================

const response = $input.first().json;
const candidateName = $('Build Prompt').first().json.candidateName;

// Navigate the Gemini response structure
let htmlContent = '';

try {
  htmlContent = response.candidates[0].content.parts[0].text;
} catch (e) {
  throw new Error('Failed to extract text from Gemini response: ' + JSON.stringify(response).substring(0, 500));
}

// Clean up: remove markdown code fences if present
htmlContent = htmlContent.replace(/^```html\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();

// Ensure it starts with <!DOCTYPE html>
if (!htmlContent.toLowerCase().startsWith('<!doctype')) {
  // If Gemini returned just the body, wrap it
  htmlContent = `<!DOCTYPE html>\n<html>\n<head><meta charset="utf-8"><title>${candidateName} Resume</title></head>\n<body>${htmlContent}</body>\n</html>`;
}

return [{
  json: {
    html: htmlContent,
    candidateName: candidateName
  }
}];
